starterCode.javascript:
// Import express framework
const express = require('express');

// Create an express app
const app = express();

// Configure the express.static middleware to serve static files from the /public directory
app.use('/public', express.static('public'));

// Configure a catch-all route to serve index.html
app.get('*', (req, res) => {
  res.sendFile('index.html', { root: __dirname + '/public' });
});

// Start the server on port 3000
const PORT = 3000;
app.listen(PORT, () => {
  console.log(`Server started on port ${PORT}`);
});

starterCode.python:
// Import the express module
from flask import Flask

// Create a Flask app
app = Flask(__name__)

// Configure the static folder to serve static files
app.config['STATIC_FOLDER'] = 'public'

// Use the static_folder to serve static files
app.add_url_rule('/public/<path:path>', 'serve_static', build_only=True)

// Configure a catch-all route to serve index.html
@app.route('/', defaults={'path': ''})
@app.route('/<path:path>')
def catch_all(path):
    return app.send_static_file('index.html')

// Run the app on port 3000
if __name__ == '__main__':
    app.run(port=3000)

